@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

@if (loading)
{
    <p class="board-loading">Loading tasks...</p>
}
else if (errorMessage is not null)
{
    <p class="board-error">Error: @errorMessage</p>
}
else
{
    <div class="board-stats">
        <span>Total: @tasks.Count</span>
        <span>To Do: @todoTasks.Count</span>
        <span>In Progress: @inProgressTasks.Count</span>
        <span>Done: @doneTasks.Count</span>
        <span>Overdue: @overdueTasks.Count</span>
    </div>

    <div class="board-search">
        <input type="text" placeholder="Search tasks..." @bind="searchText" @bind:event="oninput" />
    </div>

    <div class="kanban-board">
        <KanbanColumn Title="To Do"
                      Tasks="filteredTodo"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      OnMoveRight="id => MoveTask(id, \"In Progress\")"
                      OnTaskCreated="data => CreateTask(data, \"To Do\")" />

        <KanbanColumn Title="In Progress"
                      Tasks="filteredInProgress"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      OnMoveLeft="id => MoveTask(id, \"To Do\")"
                      OnMoveRight="id => MoveTask(id, \"Done\")"
                      OnTaskCreated="data => CreateTask(data, \"In Progress\")" />

        <KanbanColumn Title="Done"
                      Tasks="filteredDone"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      OnMoveLeft="id => MoveTask(id, \"In Progress\")"
                      OnTaskCreated="data => CreateTask(data, \"Done\")" />
    </div>
}

@code {
    private List<TaskItem> tasks = new();
    private bool loading = true;
    private string? errorMessage;
    private string searchText = string.Empty;

    private List<TaskItem> todoTasks => tasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> inProgressTasks => tasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> doneTasks => tasks.Where(t => t.Status == "Done").ToList();
    private List<TaskItem> overdueTasks => tasks.Where(t => t.DueDate < DateTime.Today && t.Status != "Done").ToList();

    private List<TaskItem> filteredTodo => Filter(todoTasks);
    private List<TaskItem> filteredInProgress => Filter(inProgressTasks);
    private List<TaskItem> filteredDone => Filter(doneTasks);

    private List<TaskItem> Filter(List<TaskItem> source)
    {
        if (string.IsNullOrWhiteSpace(searchText))
            return source;
        return source.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        try
        {
            tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = tasks.First(t => t.Id == taskId);
            tasks = tasks.Select(t => t.Id == taskId ? task with { Status = newStatus } : t).ToList();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task CreateTask((string Title, string Assignee, string Priority, DateTime DueDate) data, string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            tasks.Add(created with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

